__kernel void srad_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global float* d_dN,
    __global float* d_dS,
    __global float* d_dW,
    __global float* d_dE,
    const float q0sqr,
    __global float* d_c,
    __global float* d_I)
{
    int k = get_global_id(0);
    if (k >= Ne) return;

    int i = k / Nc;
    int j = k % Nc;

    // Clamp indices to valid range to avoid out-of-bounds
    int iN_idx = iN[i];
    int iS_idx = iS[i];
    int jW_idx = jW[j];
    int jE_idx = jE[j];

    if (iN_idx < 0) iN_idx = 0;
    if (iS_idx >= Nr) iS_idx = Nr - 1;
    if (jW_idx < 0) jW_idx = 0;
    if (jE_idx >= Nc) jE_idx = Nc - 1;

    float Jc = d_I[k];

    float dN = d_I[iN_idx * Nc + j] - Jc;
    float dS = d_I[iS_idx * Nc + j] - Jc;
    float dW = d_I[i * Nc + jW_idx] - Jc;
    float dE = d_I[i * Nc + jE_idx] - Jc;

    d_dN[k] = dN;
    d_dS[k] = dS;
    d_dW[k] = dW;
    d_dE[k] = dE;

    float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);

    float L = (dN + dS + dW + dE) / Jc;

    float num = 0.5f * G2 - (1.0f / 16.0f) * (L * L);
    float den = 1.0f + 0.25f * L;
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float c = 1.0f / (1.0f + den);

    if (c < 0.0f) c = 0.0f;
    else if (c > 1.0f) c = 1.0f;

    d_c[k] = c;
}

__kernel void srad2_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global const float* d_dN,
    __global const float* d_dS,
    __global const float* d_dW,
    __global const float* d_dE,
    __global const float* d_c,
    __global float* d_I)
{
    int k = get_global_id(0);
    if (k >= Ne) return;

    int i = k / Nc;
    int j = k % Nc;

    // Clamp indices to valid range to avoid out-of-bounds
    int iS_idx = iS[i];
    int jE_idx = jE[j];

    if (iS_idx >= Nr) iS_idx = Nr - 1;
    if (jE_idx >= Nc) jE_idx = Nc - 1;

    float cN = d_c[k];
    float cS = d_c[iS_idx * Nc + j];
    float cW = d_c[k];
    float cE = d_c[i * Nc + jE_idx];

    float D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

    d_I[k] = d_I[k] + 0.25f * lambda * D;
}
